/* ============================================================
   Assets — imágenes de marca embebidas en Base64.
   Se embeben directamente (en vez de referenciarlas por ruta)
   para que html2canvas pueda generar los PDF sin errores de
   "canvas tainted" al abrir la app vía file:// (doble clic).
   ============================================================ */
const Assets = (() => {
  const LOGO = 'data:image/png;base64,';
  const WATERMARK = 'data:image/png;base64,';
  const SELLO = 'data:image/png;base64,';

  return { LOGO, WATERMARK, SELLO };
})();
